import type {
  SessionEventListener,
  SessionOnEventOptions,
  StarciteSession,
  TailEvent,
} from "@starcite/sdk";

export interface SupervisedRuntime {
  stop(): void;
}

export interface SupervisedSession
  extends Pick<StarciteSession, "disconnect" | "id"> {
  events(): readonly TailEvent[];
  on(
    eventName: "event",
    listener: SessionEventListener,
    options?: Pick<SessionOnEventOptions, "replay">
  ): () => void;
  readonly log: {
    readonly lastSeq: number;
  };
}

export interface HistorySettleOptions {
  readonly idleWindowMs?: number;
  readonly minWaitMs?: number;
  readonly pollIntervalMs?: number;
  readonly timeoutMs?: number;
}

export type RuntimeActivationSource = "history" | "live";

export interface RuntimeActivation<
  TSession extends SupervisedSession = SupervisedSession,
> {
  readonly initialEvent: TailEvent;
  readonly session: TSession;
  readonly sessionId: string;
  readonly source: RuntimeActivationSource;
}

export interface SessionSupervisorLogger {
  error(message: string, error?: unknown): void;
  info(message: string): void;
}

type MaybePromise<T> = Promise<T> | T;

export interface SessionSupervisorOptions<
  TSession extends SupervisedSession = SupervisedSession,
> {
  readonly bindSession: (sessionId: string) => Promise<TSession>;
  readonly createRuntime: (
    activation: RuntimeActivation<TSession>
  ) => SupervisedRuntime;
  readonly discoverInitialSessionIds?: () =>
    | Promise<readonly string[]>
    | readonly string[];
  readonly historySettle?: HistorySettleOptions;
  readonly isSessionActive?: (sessionId: string) => MaybePromise<boolean>;
  readonly logger?: SessionSupervisorLogger;
  readonly shouldStartRuntime: (
    event: TailEvent,
    session: TSession
  ) => MaybePromise<boolean>;
  readonly shouldStartRuntimeFromHistory?: (
    session: TSession
  ) => MaybePromise<boolean>;
  readonly subscribeDiscoveredSessionIds?: (
    listener: (sessionId: string) => void
  ) => () => void;
  readonly subscribeReleasedSessionIds?: (
    listener: (sessionId: string) => void
  ) => () => void;
}

interface SessionWatcher<TSession extends SupervisedSession> {
  readonly session: TSession;
  readonly unsubscribe: () => void;
}

interface ManagedSessionRuntime<TSession extends SupervisedSession> {
  readonly runtime: SupervisedRuntime;
  readonly session: TSession;
}

const DEFAULT_HISTORY_SETTLE: Required<HistorySettleOptions> = {
  idleWindowMs: 100,
  minWaitMs: 500,
  pollIntervalMs: 25,
  timeoutMs: 1500,
};

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => {
    globalThis.setTimeout(resolve, ms);
  });
}

export class StarciteSessionSupervisor<
  TSession extends SupervisedSession = SupervisedSession,
> {
  private readonly bindSession: (sessionId: string) => Promise<TSession>;
  private readonly createRuntime: SessionSupervisorOptions<TSession>["createRuntime"];
  private readonly discoverInitialSessionIds: SessionSupervisorOptions<TSession>["discoverInitialSessionIds"];
  private readonly historySettle: Required<HistorySettleOptions>;
  private readonly isSessionActive: (
    sessionId: string
  ) => MaybePromise<boolean>;
  private readonly logger: SessionSupervisorLogger | undefined;
  private readonly shouldStartRuntime: SessionSupervisorOptions<TSession>["shouldStartRuntime"];
  private readonly shouldStartRuntimeFromHistory: SessionSupervisorOptions<TSession>["shouldStartRuntimeFromHistory"];
  private readonly subscribeReleasedSessionIds: SessionSupervisorOptions<TSession>["subscribeReleasedSessionIds"];
  private readonly subscribeDiscoveredSessionIds: SessionSupervisorOptions<TSession>["subscribeDiscoveredSessionIds"];
  private discoveryUnsub: (() => void) | undefined;
  private releaseUnsub: (() => void) | undefined;
  private readonly pendingSessionIds = new Set<string>();
  private readonly releasedSessionIds = new Set<string>();
  private readonly runtimes = new Map<
    string,
    ManagedSessionRuntime<TSession>
  >();
  private readonly watchers = new Map<string, SessionWatcher<TSession>>();

  constructor(options: SessionSupervisorOptions<TSession>) {
    this.bindSession = options.bindSession;
    this.createRuntime = options.createRuntime;
    this.discoverInitialSessionIds = options.discoverInitialSessionIds;
    this.historySettle = {
      ...DEFAULT_HISTORY_SETTLE,
      ...(options.historySettle ?? {}),
    };
    this.isSessionActive = options.isSessionActive ?? (() => true);
    this.logger = options.logger;
    this.shouldStartRuntime = options.shouldStartRuntime;
    this.shouldStartRuntimeFromHistory = options.shouldStartRuntimeFromHistory;
    this.subscribeReleasedSessionIds = options.subscribeReleasedSessionIds;
    this.subscribeDiscoveredSessionIds = options.subscribeDiscoveredSessionIds;
  }

  async start(): Promise<void> {
    const initialSessionIds = await this.discoverInitialSessionIds?.();

    if (initialSessionIds) {
      for (const sessionId of initialSessionIds) {
        await this.watchSession(sessionId);
      }
    }

    this.discoveryUnsub = this.subscribeDiscoveredSessionIds?.((sessionId) => {
      this.watchSession(sessionId).catch((error) => {
        this.logger?.error(
          `[starcite-session-supervisor] failed to watch session ${sessionId}`,
          error
        );
      });
    });
    this.releaseUnsub = this.subscribeReleasedSessionIds?.((sessionId) => {
      this.releaseSession(sessionId);
    });
  }

  stop(): void {
    this.discoveryUnsub?.();
    this.discoveryUnsub = undefined;
    this.releaseUnsub?.();
    this.releaseUnsub = undefined;

    for (const [, managedRuntime] of this.runtimes) {
      managedRuntime.runtime.stop();
    }
    this.runtimes.clear();

    for (const [, watcher] of this.watchers) {
      watcher.unsubscribe();
      watcher.session.disconnect();
    }
    this.watchers.clear();
    this.pendingSessionIds.clear();
    this.releasedSessionIds.clear();
  }

  private async watchSession(sessionId: string): Promise<void> {
    if (!(await this.isSessionActive(sessionId))) {
      return;
    }

    if (
      this.pendingSessionIds.has(sessionId) ||
      this.watchers.has(sessionId) ||
      this.runtimes.has(sessionId)
    ) {
      return;
    }

    this.releasedSessionIds.delete(sessionId);
    this.pendingSessionIds.add(sessionId);

    try {
      const session = await this.bindSession(sessionId);
      if (
        this.releasedSessionIds.has(sessionId) ||
        !(await this.isSessionActive(sessionId))
      ) {
        session.disconnect();
        return;
      }

      if (this.historySettle.minWaitMs > 0) {
        await sleep(this.historySettle.minWaitMs);
      }

      const historyFloorSeq = await this.awaitSessionHistorySettled(session);
      if (this.releasedSessionIds.has(sessionId)) {
        session.disconnect();
        return;
      }

      if ((await this.shouldStartRuntimeFromHistory?.(session)) ?? false) {
        const retainedEvents = [...session.events()].sort(
          (left, right) => right.seq - left.seq
        );

        for (const event of retainedEvents) {
          if (await this.shouldStartRuntime(event, session)) {
            this.startRuntime({
              initialEvent: event,
              session,
              sessionId,
              source: "history",
            });
            return;
          }
        }
      }

      const unsubscribe = session.on(
        "event",
        async (event: TailEvent) => {
          if (event.seq <= historyFloorSeq) {
            return;
          }

          if (!(await this.isSessionActive(sessionId))) {
            return;
          }

          if (!(await this.shouldStartRuntime(event, session))) {
            return;
          }

          this.startRuntime({
            initialEvent: event,
            session,
            sessionId,
            source: "live",
          });
        },
        { replay: false }
      );

      this.watchers.set(sessionId, {
        session,
        unsubscribe,
      });
      this.logger?.info(
        `[starcite-session-supervisor] watching session ${sessionId}`
      );
    } finally {
      this.pendingSessionIds.delete(sessionId);
    }
  }

  private releaseSession(sessionId: string): void {
    this.releasedSessionIds.add(sessionId);

    const watcher = this.watchers.get(sessionId);
    if (watcher) {
      watcher.unsubscribe();
      watcher.session.disconnect();
      this.watchers.delete(sessionId);
    }

    const runtime = this.runtimes.get(sessionId);
    if (runtime) {
      runtime.runtime.stop();
      this.runtimes.delete(sessionId);
    }

    this.logger?.info(
      `[starcite-session-supervisor] released session ${sessionId}`
    );
  }

  private async awaitSessionHistorySettled(session: TSession): Promise<number> {
    const deadline = Date.now() + this.historySettle.timeoutMs;
    let previousLastSeq = -1;
    let stableSinceMs = Date.now();

    while (Date.now() < deadline) {
      const lastSeq = session.log.lastSeq;

      if (lastSeq !== previousLastSeq) {
        previousLastSeq = lastSeq;
        stableSinceMs = Date.now();
      } else if (
        Date.now() - stableSinceMs >=
        this.historySettle.idleWindowMs
      ) {
        return lastSeq;
      }

      if (this.historySettle.pollIntervalMs > 0) {
        await sleep(this.historySettle.pollIntervalMs);
      } else {
        await Promise.resolve();
      }
    }

    return session.log.lastSeq;
  }

  private startRuntime(activation: RuntimeActivation<TSession>): void {
    const watcher = this.watchers.get(activation.sessionId);
    if (watcher) {
      watcher.unsubscribe();
      this.watchers.delete(activation.sessionId);
    }

    if (this.runtimes.has(activation.sessionId)) {
      return;
    }

    const runtime = this.createRuntime(activation);

    this.runtimes.set(activation.sessionId, {
      runtime,
      session: activation.session,
    });
    this.logger?.info(
      `[starcite-session-supervisor] started runtime for session ${activation.sessionId}`
    );
  }
}
